+
+function getFileTreeDirectoryPaths(paths: string[]): string[] {
+  const directoryPaths = new Set<string>();
+  for (const path of paths) {
+    const trimmedPath = path.replace(/^\/+|\/+$/g, '');
+    if (!trimmedPath) {
+      continue;
+    }
