+    const segments = trimmedPath.split('/');
+    const terminalSegmentCount = path.endsWith('/')
+      ? segments.length
+      : segments.length - 1;
+    for (let index = 1; index <= terminalSegmentCount; index += 1) {
+      directoryPaths.add(`${segments.slice(0, index).join('/')}/`);
+    }
+  }
