+.yyork-files-workspace {
+  display: flex;
+  height: 100%;
+  min-height: 0;
+  width: 100%;
+  max-width: 100%;
+  overflow: hidden;
+  background: var(--background);
+}
+
+.yyork-files-workspace--collapsed {
+  display: flex;
+}
+
+.yyork-file-preview-pane {
+  position: relative;
+  flex: 1 1 auto;
+  height: 100%;
+  min-height: 0;
+  min-width: 0;
+  width: 100%;
+  background: var(--background);
+}
+
+.yyork-file-preview-floating-action {
+  position: absolute;
+  top: 0.5rem;
+  right: 0.5rem;
+  z-index: 1;
+  display: flex;
+}
+
+.yyork-file-preview-header {
+  display: flex;
+  min-height: 2.25rem;
+  flex-shrink: 0;
+  align-items: center;
+  gap: 0.5rem;
+  border-bottom: 1px solid var(--border);
+  padding: 1rem;
+  color: var(--foreground);
+  font-size: 0.75rem;
+  font-weight: 500;
+  line-height: 1rem;
+}
+
+.yyork-file-preview-body {
+  display: flex;
+  min-height: 0;
+  flex: 1;
+  flex-direction: column;
+  overflow: hidden;
+}
+
+.yyork-file-code-scroll {
+  height: 100%;
+  min-height: 0;
+  min-width: 100%;
+  flex: 1;
+  overflow: hidden;
+}
+
+.yyork-file-code-viewer {
+  height: 100%;
+  min-height: 0;
+  width: 100%;
+  overflow: auto;
+  scrollbar-gutter: stable;
+  background: var(--background);
+  --diffs-font-family: var(--font-mono);
+  --diffs-font-size: 0.75rem;
+  --diffs-line-height: 1.45;
+}
+
+.yyork-file-tree-shell {
+  box-sizing: border-box;
+  gap: 0.375rem;
+  padding: 0.5rem 0.375rem 0.5rem;
+  background: var(--background);
+}
+
+.yyork-file-tree-pane {
+  height: 100%;
+  min-width: 0;
+}
+
+.yyork-file-tree-resizable-panel {
+  min-width: 0;
+}
+
+.yyork-file-tree-resize-handle {
+  cursor: col-resize;
+}
+
